using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed from "Discriminator" to "$type".
            // Existing documents use "Discriminator", so pin the old name and value to stay
            // compatible with the 500K docs already in the container AND with direct SQL
            // queries that reference c.Discriminator.
            b.HasDiscriminator<string>("Discriminator")
             .HasValue<Product>("Product");

            // BREAKING CHANGE 2 — id synthesis no longer includes the discriminator.
            // EF8 wrote id = "Product|123"; EF9 writes id = "123".
            // Override id generation to keep the legacy "Product|{key}" format so
            // existing documents can still be read, updated, and deleted.
            b.Property<string>("__id")
             .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex now throws for the Cosmos provider
            // (it was silently ignored in EF8).  Removed the HasIndex call.
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

/// <summary>
/// Generates Cosmos id values in the legacy EF Core 8 format: "{Discriminator}|{PrimaryKey}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    protected override string NextValue(EntityEntry entry)
    {
        var discriminator = entry.Property("Discriminator").CurrentValue?.ToString();
        var key = entry.Property("Id").CurrentValue;
        return $"{discriminator}|{key}";
    }
}

