using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // BREAKING CHANGE 4 — Synchronous LINQ operators (ToList, First, Single, …)
    // now throw at runtime on the Cosmos provider.  All queries must be async.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we pinned the discriminator
        // property name to "Discriminator" in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Changed from .ToList() → .ToListAsync()
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

